 const SVGParser = require('./svg-parser');

+/**
+ * Remove potentially executable/scriptable elements and attributes from parsed SVG.
+ * This prevents untrusted SVG content from introducing DOM XSS when rendered.
+ * @param {Element} root Parsed SVG root element.
+ */
+const sanitizeSvg = root => {
+    if (!root || !root.querySelectorAll) return;
+
+    // Remove elements which can execute script or embed active content.
+    const blockedElements = root.querySelectorAll('script,foreignObject');
+    for (const el of blockedElements) {
+        if (el.parentNode) {
+            el.parentNode.removeChild(el);
+        }
+    }
+
+    // Remove inline event handlers and javascript: URLs.
+    const allElements = root.querySelectorAll('*');
+    for (const el of allElements) {
+        for (const attr of Array.from(el.attributes || [])) {
+            const name = attr.name;
+            const value = attr.value;
+            if (/^on/i.test(name)) {
+                el.removeAttribute(name);
+            } else if ((name === 'href' || name === 'xlink:href') && /^\s*javascript:/i.test(value)) {
+                el.removeAttribute(name);
+            }
+        }
+    }
+};
+
 /**
  * @param {string} svgString raw SVG string to fix
  * @returns {string} fixed SVG string
  */
 module.exports = function (svgString) {
