--- /dev/null
+++ b/src/quote/parser.rs
@@ -0,0 +1,27 @@
+use crate::error::{Error, Result};
+
+pub struct ParsedQeReport {
+    pub mrsigner: String,
+    pub isvprodid: u16,
+    pub isvsvn: u16,
+}
+
+pub fn parse_qe_report(quote: &[u8]) -> Result<ParsedQeReport> {
+    if quote.len() < 388 {
+        return Err(Error::InvalidCollateral("quote"));
+    }
+
+    // SGX/TDX QE report body layout fields used here:
+    // - MRSIGNER: bytes [176..208]
+    // - ISVPRODID: bytes [304..306]
+    // - ISVSVN: bytes [306..308]
+    let mrsigner = hex::encode(&quote[176..208]);
+    let isvprodid = u16::from_le_bytes([quote[304], quote[305]]);
+    let isvsvn = u16::from_le_bytes([quote[306], quote[307]]);
+
+    Ok(ParsedQeReport {
+        mrsigner,
+        isvprodid,
+        isvsvn,
+    })
+}
