@@ -1,5 +1,29 @@
 use crate::error::{Error, Result};

+pub fn verify_pck_certificate_chain(
+    msg: &[u8],
+    signature: &str,
+    issuer_chain_pem: &str,
+) -> Result<()> {
+    let certs = pem::parse_many(issuer_chain_pem.as_bytes())
+        .map_err(|_| Error::CertificateVerification)?;
+    let signing_cert = certs.first().ok_or(Error::CertificateVerification)?;
+
+    let sig = hex::decode(signature).map_err(|_| Error::CertificateVerification)?;
+    let cert = x509_parser::parse_x509_certificate(signing_cert.contents())
+        .map_err(|_| Error::CertificateVerification)?
+        .1;
+
+    let spki = cert.public_key().raw.to_owned();
+    let key = ring::signature::UnparsedPublicKey::new(
+        &ring::signature::RSA_PKCS1_2048_8192_SHA256,
+        spki,
+    );
+    key.verify(msg, &sig)
+        .map_err(|_| Error::CertificateVerification)?;
+
+    Ok(())
+}
+
 pub fn verify_certificate_chain(_chain: &str) -> Result<()> {
     Ok(())
 }
